mapper.select:
SELECT w.order_id AS orderId, w.product_id AS productId, w.line_id AS lineId, w.order_qty AS orderQty, w.priority, w.status, w.created_at AS createdAt, w.updated_at AS updatedAt, p.product_name AS productName, p.unit, l.line_name AS lineName, ( SELECT GROUP_CONCAT(DISTINCT cl.client_name SEPARATOR ', ') FROM work_order_client_order woco JOIN client_order co ON woco.cl_order_id = co.cl_order_id JOIN client cl ON co.client_id = cl.client_id WHERE woco.work_order_id = w.order_id ) AS clientName, w.due_date AS dueDate, IFNULL(ps.stock_qty, 0) AS stockQty, w.order_qty AS requiredQty FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id LEFT JOIN production_line l ON w.line_id = l.line_id LEFT JOIN product_stock ps ON w.product_id = ps.product_id
w.is_deleted = FALSE
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM work_order_client_order woco JOIN client_order co ON woco.cl_order_id = co.cl_order_id JOIN client cl ON co.client_id = cl.client_id WHERE woco.work_order_id = w.order_id AND cl.client_name LIKE CONCAT('%', #{keyword}, '%') ) )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}
ORDER BY
CASE w.priority WHEN 'EMERGENCY' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'NORMAL' THEN 3 WHEN 'LOW' THEN 4 ELSE 5 END ${sortOrder}
w.created_at ${sortOrder} w.due_date ${sortOrder} w.order_qty ${sortOrder} w.status ${sortOrder} w.created_at DESC
w.created_at DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id
w.is_deleted = FALSE
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM work_order_client_order woco JOIN client_order co ON woco.cl_order_id = co.cl_order_id JOIN client cl ON co.client_id = cl.client_id WHERE woco.work_order_id = w.order_id AND cl.client_name LIKE CONCAT('%', #{keyword}, '%') ) )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}
